import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

export default function Home() {
    const [videos, setVideos] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchVideos();
    }, []);

    const fetchVideos = async () => {
        try {
            const response = await axios.get('/videos/');
            setVideos(response.data.results || response.data);
        } catch (error) {
            console.error('Error fetching videos:', error);
        } finally {
            setLoading(false);
        }
    };

    if (loading) {
        return <div className="flex justify-center items-center h-screen text-white">Загрузка...</div>;
    }

    return (
        <div className="container mx-auto px-4 py-8">
            <h1 className="text-3xl font-bold text-white mb-8">Все видео</h1>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {videos.map(video => (
                    <Link key={video.id} to={`/video/${video.id}`} className="block group">
                        <div className="bg-gray-900 rounded-lg overflow-hidden transition-transform group-hover:scale-105">
                            <div className="relative pb-[56.25%]">
                                <div className="absolute inset-0 bg-gray-800 flex items-center justify-center">
                                    <span className="text-gray-600">🎬</span>
                                </div>
                            </div>
                            <div className="p-3">
                                <h3 className="font-semibold text-white line-clamp-2">{video.title}</h3>
                                <p className="text-sm text-gray-400 mt-1">{video.author?.username}</p>
                                <p className="text-xs text-gray-500 mt-1">{video.views} просмотров</p>
                            </div>
                        </div>
                    </Link>
                ))}
            </div>
            {videos.length === 0 && (
                <div className="text-center text-gray-500 mt-20">
                    <p className="text-xl">Видео пока нет</p>
                    <p className="mt-2">Станьте первым, кто загрузит видео!</p>
                </div>
            )}
        </div>
    );
}
